sql:
SELECT keywords, COUNT(*) as total_speeches
FROM speeches
GROUP BY keywords;

SELECT speech_id, title, year, speech_text
FROM speeches
ORDER BY year DESC;

SELECT title
FROM speeches
WHERE speech_text LIKE '%Economy%';

SELECT MAX(duration) AS longest_duration
FROM speeches
WHERE year = 2020;

SELECT speech_id, COUNT(*) AS total_questions
FROM speech_questions
GROUP BY speech_id;

SELECT title, location, date, duration, audio_file 
FROM speeches 
WHERE speech_id = 1;

external_knowledge:
- 'Tech conversations' refers to speeches with the topic 'Technology'.;
- 'Since the turn of the millennium' means after or including the year 2000. ;
- 'Google representatives' refers to speakers affiliated with the organization 'Google'.;

